433	func CheckRedisPing(check *schema.RedisCheck) AssertionResult {
434		host := check.Host
435		if host == "" {
436			host = "localhost"
437		}
438		port := check.Port
439		if port == 0 {
440			port = 6379
441		}
442		addr := fmt.Sprintf("%s:%d", host, port)
443		conn, err := net.DialTimeout("tcp", addr, 5*time.Second)
444		if err != nil {
445			return AssertionResult{Type: "redis_ping", Expected: addr, Actual: err.Error(), Passed: false}
446		}
447		defer conn.Close()
448		conn.SetDeadline(time.Now().Add(5 * time.Second)) //nolint:errcheck
449	
450		// Optional AUTH
451		if check.Password != "" {
452			authCmd := fmt.Sprintf("*2\r\n$4\r\nAUTH\r\n$%d\r\n%s\r\n", len(check.Password), check.Password)
453			if _, err := conn.Write([]byte(authCmd)); err != nil {
454				return AssertionResult{Type: "redis_ping", Expected: addr, Actual: "auth write error: " + err.Error(), Passed: false}
455			}
456			buf := make([]byte, 128)
457			n, _ := conn.Read(buf)
458			if !strings.HasPrefix(string(buf[:n]), "+OK") {
459				return AssertionResult{Type: "redis_ping", Expected: "+OK", Actual: strings.TrimSpace(string(buf[:n])), Passed: false}
460			}
461		}
462	
463		if _, err := conn.Write([]byte("*1\r\n$4\r\nPING\r\n")); err != nil {
464			return AssertionResult{Type: "redis_ping", Expected: addr, Actual: err.Error(), Passed: false}
465		}
466		buf := make([]byte, 64)
467		n, err := conn.Read(buf)
468		if err != nil {
469			return AssertionResult{Type: "redis_ping", Expected: "+PONG", Actual: err.Error(), Passed: false}
470		}
471		reply := strings.TrimSpace(string(buf[:n]))
472		if !strings.HasPrefix(reply, "+PONG") {
473			return AssertionResult{Type: "redis_ping", Expected: "+PONG", Actual: reply, Passed: false}
474		}
475		return AssertionResult{Type: "redis_ping", Expected: addr, Actual: "PONG", Passed: true}
476	}
